#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>
#include <string.h>

int main(void) {
    int fd = open("/tmp/kf_blocks_test", O_CREAT | O_WRONLY | O_TRUNC, 0600);
    char buf[4096];
    memset(buf, 'A', sizeof(buf));
    write(fd, buf, sizeof(buf));
    close(fd);

    struct stat st;
    stat("/tmp/kf_blocks_test", &st);
    /* st_size est toujours exact (taille logique) */
    printf("st_size: %lld bytes\n", (long long)st.st_size);
    /* st_blksize varie selon le FS, mais toujours > 0 */
    printf("st_blksize > 0: %s\n", st.st_blksize > 0 ? "yes" : "no");
    /* st_blocks en unites 512-octets, toujours > 0 pour un fichier non-creux */
    printf("st_blocks > 0: %s\n", st.st_blocks > 0 ? "yes" : "no");
    /* Calcul : blocs de 512B -> blocs de 4K */
    long long blocks_4k = st.st_blocks / 8;
    printf("blocks_4k >= 1: %s\n", blocks_4k >= 1 ? "yes" : "no");

    unlink("/tmp/kf_blocks_test");
    return 0;
}

